#include <iostream>
using namespace std;

class Rectangle {
 int width, height;
public:
 // Default Constructor
 Rectangle() {
 width = height = 0;
 cout << "Default Constructor" << endl;
 }

 // Parameterized Constructor
 Rectangle(int w, int h) {
 width = w;
 height = h;
 cout << "Parameterized Constructor" << endl;
 }

 // Copy Constructor
 Rectangle(const Rectangle& r) {
 width = r.width;
 height = r.height;
 cout << "Copy Constructor" << endl;
 }

 void display() {
 cout << "Width: " << width << ", Height: " << height << endl;
 }
};

int main() {
 Rectangle r1; // Calls default
 Rectangle r2(10, 5); // Calls parameterized
 Rectangle r3 = r2; // Calls copy
 Rectangle r4(r2); // Calls copy

 r1.display();
r2.display();
r3.display();
r4.display();

 return 0;
}

#include <iostream>
using namespace std;

class Point {
 int x, y;
public:
 // Using member initializer list (efficient)
 Point(int a, int b) : x(a), y(b) {
 // Body can be empty or have additional code
 }

 void display() {
 cout << "(" << x << ", " << y << ")" << endl;
 }
};

class Line {
 const int length; // const member
 Point p1, p2; // object members
public:
 // MUST use initializer list for const and objects
 Line(int x1, int y1, int x2, int y2, int len) 
 : p1(x1, y1), p2(x2, y2), length(len) {
 cout << "Line constructor" << endl;
 }

 void display() {
 cout << "Line from "; p1.display(); cout << " to "; p2.display();
 cout << " Length: " << length << endl;
 }
};

int main() {
 Line l(0, 0, 10, 10, 14);
 l.display();
 return 0;
}

#include <iostream>
#include <cstring>
using namespace std;

class String {
 char* str;
 int len;
public:
 // Parameterized Constructor
 String(const char* s) {
 len = strlen(s);
 str = new char[len + 1];
 strcpy(str, s);
 cout << "Parameterized Constructor" << endl;
 }

 // Copy Constructor (Deep Copy)
 String(const String& s) {
 len = s.len;
 str = new char[len + 1];
 strcpy(str, s.str);
 cout << "Copy Constructor (Deep)" << endl;
 }

 // Destructor
 ~String() {
 delete[] str;
 }

 void display() {
 cout << str << endl;
 }
};

void printByValue(String s) {
 s.display();
}

int main() {
 String s1("Hello");
 String s2 = s1; // Copy constructor called
 printByValue(s1); // Copy constructor called (pass by value)

 return 0;
}

#include <iostream>
using namespace std;

class Base {
 int x;
public:
 Base() {
 x = 0;
 cout << "Base Constructor" << endl;
 }
 Base(int a) {
 x = a;
 cout << "Base Parameterized Constructor" << endl;
 }
 ~Base() {
 cout << "Base Destructor" << endl;
 }
};

class Derived : public Base {
 int y;
public:
 Derived() {
 y = 0;
 cout << "Derived Constructor" << endl;
 }
 Derived(int a, int b) : Base(a) {
 y = b;
 cout << "Derived Parameterized Constructor" << endl;
 }
 ~Derived() {
 cout << "Derived Destructor" << endl;
 }
};

int main() {
 cout << "Creating object..." << endl;
 Derived d(10, 20);
 cout << "Object created" << endl << endl;
 cout << "Destroying object..." << endl;
 return 0;
}
